#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932

long M = 2147483647;
int A = 1103515245;
int C = 12345;

double roundDouble_opencl(double value) {
    int newValue = (int)(value);
    if(value - newValue < 0.5)
        return (double)newValue;
    else
        return (double)(newValue + 1);
}

double randu_opencl(int * seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double) M));
}

double randn_opencl(int * seed, int index) {
    double u = randu_opencl(seed, index);
    double v = randu_opencl(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

kernel void init_arrays_kernel(double * arrayX, double * arrayY, double xe, double ye, int Nparticles) {
    int x = get_global_id(0);
    if(x < Nparticles) {
        arrayX[x] = xe;
        arrayY[x] = ye;
    }
}

kernel void init_weights_kernel(double * weights, int Nparticles) {
    int x = get_global_id(0);
    if(x < Nparticles) {
        weights[x] = 1.0 / ((double)(Nparticles));
    }
}

kernel void strelDisk_kernel(int * disk, int radius, int diameter) {
    int x = get_global_id(0);
    int y = get_global_id(1);
    if(x < diameter && y < diameter) {
        double distance = sqrt(pow((double)(x - radius + 1), 2) + pow((double)(y - radius + 1), 2));
        if(distance < radius)
            disk[x * diameter + y] = 1;
        else
            disk[x * diameter + y] = 0;
    }
}

kernel void setIf_kernel(unsigned char * array3D, int testValue, int newValue, int dimX, int dimY, int dimZ) {
    int x = get_global_id(0);
    int y = get_global_id(1);
    int z = get_global_id(2);
    if(x < dimX && y < dimY && z < dimZ) {
        int idx = x * dimY * dimZ + y * dimZ + z;
        if(array3D[idx] == testValue)
            array3D[idx] = newValue;
    }
}

kernel void addNoise_kernel(unsigned char * array3D, int * seed, int dimX, int dimY, int dimZ) {
    int x = get_global_id(0);
    int y = get_global_id(1);
    int z = get_global_id(2);
    if(x < dimX && y < dimY && z < dimZ) {
        int idx = x * dimY * dimZ + y * dimZ + z;
        double noise = 5.0 * randn_opencl(seed, 0);
        array3D[idx] = array3D[idx] + (unsigned char)(noise);
    }
}

