kernel void error_propagation_kernel(double * arrayX, double * arrayY, int * seed, int Nparticles) {
    int x = get_global_id(0);
    if(x < Nparticles) {
        arrayX[x] += 1.0 + 5.0 * randn_opencl(seed, x);
        arrayY[x] += -2.0 + 2.0 * randn_opencl(seed, x);
    }
}

kernel void likelihood_kernel(double * arrayX, double * arrayY, double * xj, double * yj, double * CDF, int * ind, 
                              int * objxy, double * likelihood, unsigned char * I, double * u, double * weights,
                              int Nparticles, int countOnes, int max_size, int k, int IszY, int Nfr, int * seed, double * partial_sums) {
    int x = get_global_id(0);
    if(x < Nparticles) {
        for(int y = 0; y < countOnes; y++) {
            int indX = (int)roundDouble_opencl(arrayX[x]) + objxy[y * 2 + 1];
            int indY = (int)roundDouble_opencl(arrayY[x]) + objxy[y * 2];
            int idx = indX * IszY * Nfr + indY * Nfr + k;
            if(idx >= max_size)
                idx = 0;
            ind[x * countOnes + y] = idx;
        }

        likelihood[x] = 0.0;
        for(int y = 0; y < countOnes; y++) {
            int val = I[ind[x * countOnes + y]];
            likelihood[x] += (pow((val - 100), 2) - pow((val - 228), 2)) / 50.0;
        }
        likelihood[x] = likelihood[x] / ((double)countOnes);

        weights[x] = weights[x] * exp(likelihood[x]);

        partial_sums[x] = weights[x];
        if(x > 0) {
            partial_sums[x] += partial_sums[x - 1];
        }

        CDF[x] = partial_sums[x];

        if(x == 0) {
            double u1 = (1.0 / ((double)(Nparticles))) * randu_opencl(seed, 0);
            u[0] = u1;
        }
        u[x] = (1.0 / ((double)(Nparticles))) * randu_opencl(seed, 0) + x / ((double)(Nparticles));
    }
}

kernel void sum_weights_kernel(double * partial_sums, int Nparticles) {
    int x = get_global_id(0);
    if(x < Nparticles) {
        if(x > 0) {
            partial_sums[x] += partial_sums[x - 1];
        }
    }
}

kernel void normalize_weights_kernel(double * weights, int Nparticles, double * partial_sums, double * CDF, double * u, int * seed) {
    int x = get_global_id(0);
    if(x < Nparticles) {
        double sumWeights = partial_sums[Nparticles - 1];
        weights[x] = weights[x] / sumWeights;
        CDF[x] = partial_sums[x];

        if(x == 0) {
            double u1 = (1.0 / ((double)(Nparticles))) * randu_opencl(seed, 0);
            u[0] = u1;
        }
        u[x] = (1.0 / ((double)(Nparticles))) * randu_opencl(seed, 0) + x / ((double)(Nparticles));
    }
}

kernel void calculate_xe_ye_kernel(double * arrayX, double * arrayY, double * weights, int Nparticles, double * xe_result, double * ye_result) {
    int x = get_global_id(0);
    if(x < Nparticles) {
        xe_result[0] += arrayX[x] * weights[x];
        ye_result[0] += arrayY[x] * weights[x];
    }
}

