#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932

int findIndex_opencl(double * CDF, int lengthCDF, double value) {
    int index = -1;
    for(int x = 0; x < lengthCDF; x++) {
        if(CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if(index == -1) {
        return lengthCDF - 1;
    }
    return index;
}

int findIndexBin_opencl(double * CDF, int beginIndex, int endIndex, double value) {
    if(endIndex < beginIndex)
        return -1;
    int middleIndex = beginIndex + ((endIndex - beginIndex) / 2);

    if(CDF[middleIndex] >= value) {
        if(middleIndex == 0)
            return middleIndex;
        else if(CDF[middleIndex - 1] < value)
            return middleIndex;
        else if(CDF[middleIndex - 1] == value) {
            while(middleIndex > 0 && CDF[middleIndex - 1] == value)
                middleIndex--;
            return middleIndex;
        }
    }
    if(CDF[middleIndex] > value)
        return findIndexBin_opencl(CDF, beginIndex, middleIndex + 1, value);
    return findIndexBin_opencl(CDF, middleIndex - 1, endIndex, value);
}

kernel void find_index_kernel(double * arrayX, double * arrayY, double * CDF, double * u, double * xj, double * yj, double * weights, int Nparticles) {
    int j = get_global_id(0);
    if(j < Nparticles) {
        int i = findIndex_opencl(CDF, Nparticles, u[j]);
        if(i == -1)
            i = Nparticles - 1;
        xj[j] = arrayX[i];
        yj[j] = arrayY[i];
    }
}

kernel void resample_kernel(double * arrayX, double * arrayY, double * xj, double * yj, double * weights, int Nparticles) {
    int x = get_global_id(0);
    if(x < Nparticles) {
        arrayX[x] = xj[x];
        arrayY[x] = yj[x];
        weights[x] = 1.0 / ((double)(Nparticles));
    }
}

kernel void dilate_matrix_kernel(unsigned char * matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while(startX < 0)
        startX++;
    int startY = posY - error;
    while(startY < 0)
        startY++;
    int endX = posX + error;
    while(endX > dimX)
        endX--;
    int endY = posY + error;
    while(endY > dimY)
        endY--;

    int x = get_global_id(0);
    int y = get_global_id(1);
    if(x >= startX && x < endX && y >= startY && y < endY) {
        double distance = sqrt(pow((double)(x - posX), 2) + pow((double)(y - posY), 2));
        if(distance < error)
            matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
    }
}

kernel void imdilate_disk_kernel(unsigned char * matrix, unsigned char * newMatrix, int dimX, int dimY, int dimZ, int error) {
    int x = get_global_id(0);
    int y = get_global_id(1);
    int z = get_global_id(2);
    if(x < dimX && y < dimY && z < dimZ) {
        if(matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
            int startX = x - error;
            while(startX < 0) startX++;
            int startY = y - error;
            while(startY < 0) startY++;
            int endX = x + error;
            while(endX > dimX) endX--;
            int endY = y + error;
            while(endY > dimY) endY--;

            for(int ix = startX; ix < endX; ix++) {
                for(int iy = startY; iy < endY; iy++) {
                    double distance = sqrt(pow((double)(ix - x), 2) + pow((double)(iy - y), 2));
                    if(distance < error)
                        newMatrix[ix * dimY * dimZ + iy * dimZ + z] = 1;
                }
            }
        }
    }
}

kernel void copy_matrix_kernel(unsigned char * I, unsigned char * newMatrix, int dimX, int dimY, int dimZ) {
    int x = get_global_id(0);
    int y = get_global_id(1);
    int z = get_global_id(2);
    if(x < dimX && y < dimY && z < dimZ) {
        I[x * dimY * dimZ + y * dimZ + z] = newMatrix[x * dimY * dimZ + y * dimZ + z];
    }
}

kernel videoSequence_kernel(unsigned char * I, int IszX, int IszY, int Nfr) {
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)roundDouble_opencl(IszY / 2.0);
    int y0 = (int)roundDouble_opencl(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    for(int k = 1; k < Nfr; k++) {
        int xk = abs(x0 + (k - 1));
        int yk = abs(y0 - 2 * (k - 1));
        int pos = yk * IszY * Nfr + xk * Nfr + k;
        if(pos >= max_size)
            pos = 0;
        I[pos] = 1;
    }
}
